  1→// Package namematch provides deterministic institution name matching.
  2→//
  3→// It loads all institutions and aliases from the database into in-memory maps
  4→// and resolves input names to unit_id values via a 3-tier lookup:
  5→//
  6→//  1. Exact lowercase match against institution_name
  7→//  2. Normalized match (diacritics stripped, punctuation removed, etc.)
  8→//  3. Builtin alias overrides for common external-source name variants
  9→//  4. DB alias match from search_base.institution_alias
 10→//
 11→// MatchByOPE6 and MatchByOPE8 provide direct lookups by OPE ID.
 12→package namematch
 13→
 14→import (
 15→	"context"
 16→	"fmt"
 17→	"strings"
 18→
 19→	"github.com/jackc/pgx/v5/pgxpool"
 20→)
 21→
 22→// Matcher holds in-memory lookup maps for deterministic name resolution.
 23→type Matcher struct {
 24→	exact      map[string]string // strings.ToLower(institution_name) → unit_id
 25→	normalized map[string]string // Normalize(institution_name) → unit_id
 26→	alias      map[string]string // strings.ToLower(db alias) → unit_id
 27→	ope6       map[string]string // ope6_id → unit_id
 28→	ope8       map[string]string // ope8_id → unit_id
 29→}
 30→
 31→// Load queries all institutions and aliases from the database and returns a
 32→// ready-to-use Matcher. The pool must be connected and the schema must be
 33→// populated.
 34→func Load(ctx context.Context, pool *pgxpool.Pool) (*Matcher, error) {
 35→	m := &Matcher{
 36→		exact:      make(map[string]string),
 37→		normalized: make(map[string]string),
 38→		alias:      make(map[string]string),
 39→		ope6:       make(map[string]string),
 40→		ope8:       make(map[string]string),
 41→	}
 42→
 43→	if err := m.loadInstitutions(ctx, pool); err != nil {
 44→		return nil, fmt.Errorf("namematch: load institutions: %w", err)
 45→	}
 46→	if err := m.loadAliases(ctx, pool); err != nil {
 47→		return nil, fmt.Errorf("namematch: load aliases: %w", err)
 48→	}
 49→	return m, nil
 50→}
 51→
 52→func (m *Matcher) loadInstitutions(ctx context.Context, pool *pgxpool.Pool) error {
 53→	rows, err := pool.Query(ctx,
 54→		`SELECT unit_id, institution_name, ope6_id, ope8_id FROM search_base.institution`)
 55→	if err != nil {
 56→		return err
 57→	}
 58→	defer rows.Close()
 59→
 60→	for rows.Next() {
 61→		var unitID, name, ope6, ope8 string
 62→		if err := rows.Scan(&unitID, &name, &ope6, &ope8); err != nil {
 63→			return err
 64→		}
 65→		m.exact[strings.ToLower(name)] = unitID
 66→		m.normalized[Normalize(name)] = unitID
 67→		if ope6 != "" {
 68→			m.ope6[ope6] = unitID
 69→		}
 70→		if ope8 != "" {
 71→			m.ope8[ope8] = unitID
 72→		}
 73→	}
 74→	return rows.Err()
 75→}
 76→
 77→func (m *Matcher) loadAliases(ctx context.Context, pool *pgxpool.Pool) error {
 78→	rows, err := pool.Query(ctx,
 79→		`SELECT unit_id, alias FROM search_base.institution_alias`)
 80→	if err != nil {
 81→		return err
 82→	}
 83→	defer rows.Close()
 84→
 85→	for rows.Next() {
 86→		var unitID, alias string
 87→		if err := rows.Scan(&unitID, &alias); err != nil {
 88→			return err
 89→		}
 90→		m.alias[strings.ToLower(alias)] = unitID
 91→	}
 92→	return rows.Err()
 93→}
 94→
 95→// Match resolves an institution name to its unit_id using a 3-tier lookup:
 96→//  1. Exact lowercase match
 97→//  2. Normalized match
 98→//  3. Builtin alias (normalized input → canonical name → normalized lookup)
 99→//  4. DB alias (lowercase)
100→//
101→// Returns ("", false) if no match is found.
102→func (m *Matcher) Match(name string) (unitID string, ok bool) {
103→	// Tier 1: exact lowercase
104→	lower := strings.ToLower(name)
105→	if uid, found := m.exact[lower]; found {
106→		return uid, true
107→	}
108→
109→	// Tier 2: normalized
110→	nkey := Normalize(name)
111→	if uid, found := m.normalized[nkey]; found {
112→		return uid, true
113→	}
114→
115→	// Tier 3: builtin alias → normalize canonical name → normalized lookup
116→	if canonical, found := builtinAliases[nkey]; found {
117→		if uid, found := m.normalized[Normalize(canonical)]; found {
118→			return uid, true
119→		}
120→	}
121→
122→	// Tier 4: DB alias (lowercase)
123→	if uid, found := m.alias[lower]; found {
124→		return uid, true
125→	}
126→
127→	return "", false
128→}
129→
130→// MatchByOPE6 looks up an institution by its 6-digit OPE ID.
131→func (m *Matcher) MatchByOPE6(ope6 string) (unitID string, ok bool) {
132→	uid, found := m.ope6[ope6]
133→	return uid, found
134→}
135→
136→// MatchByOPE8 looks up an institution by its 8-digit OPE ID.
137→func (m *Matcher) MatchByOPE8(ope8 string) (unitID string, ok bool) {
138→	uid, found := m.ope8[ope8]
139→	return uid, found
140→}
