111→VALUES ($1, $2, $3, $4, $5, $6)
112→ON CONFLICT (id) DO UPDATE SET
113→    publication = EXCLUDED.publication,
114→    category    = EXCLUDED.category,
115→    url         = EXCLUDED.url`
