184→func (b *RankingBuilder) flushInstitutionRankings(ctx context.Context, pool *pgxpool.Pool) error {
185→	// Group opinions by unit_id, keeping only the latest year per ranking.
186→	type key struct {
187→		unitID    string
188→		rankingID string
189→	}
190→	latest := make(map[key]Opinion)
191→	for _, op := range b.opinions {
192→		k := key{unitID: op.UnitID, rankingID: rankingID(op.PublicationSlug, op.CategorySlug)}
193→		if existing, ok := latest[k]; !ok || op.Year > existing.Year {
194→			latest[k] = op
195→		}
196→	}
197→
198→	// Group by unit_id to build per-institution JSONB.
199→	byUnit := make(map[string]map[string]any)
200→	for k, op := range latest {
201→		if byUnit[k.unitID] == nil {
202→			byUnit[k.unitID] = make(map[string]any)
203→		}
204→		byUnit[k.unitID][k.rankingID] = buildOpinionData(op)
205→	}
206→
207→	for unitID, rankings := range byUnit {
208→		rankingsJSON, err := json.Marshal(rankings)
209→		if err != nil {
210→			return fmt.Errorf("ranking: marshal institution rankings: %w", err)
211→		}
212→		inst := &dbutil.Institution{
213→			UnitID:   unitID,
214→			Rankings: rankingsJSON,
215→		}
216→		if err := dbutil.UpsertInstitution(ctx, pool, inst); err != nil {
217→			return fmt.Errorf("ranking: flush institution rankings: %w", err)
218→		}
219→	}
220→	return nil
221→}
