  9→
 10→// Option configures a Reader.
 11→type Option func(*Reader)
 12→
 13→// WithDelimiter sets the field delimiter (default: ',').
 14→func WithDelimiter(r rune) Option {
 15→	return func(cr *Reader) {
 16→		cr.csv.Comma = r
 17→	}
 18→}
 19→
 20→// WithLazyQuotes allows bare quotes in non-quoted fields and non-doubled quotes
 21→// in quoted fields (encoding/csv LazyQuotes mode).
 22→func WithLazyQuotes(b bool) Option {
 23→	return func(cr *Reader) {
 24→		cr.csv.LazyQuotes = b
 25→	}
 26→}
 27→
 28→// Reader wraps encoding/csv and maps columns by header name.
 29→// Call Next to iterate rows; each row provides named-column accessors.
 30→type Reader struct {
 31→	csv     *csv.Reader
 32→	headers map[string]int
 33→}
 34→
 35→// NewReader creates a Reader, reads the first line as column headers, and
 36→// applies any provided options. Returns an error if the header row cannot be
 37→// read or parsed.
 38→func NewReader(r io.Reader, opts ...Option) (*Reader, error) {
 39→	cr := &Reader{
 40→		csv: csv.NewReader(r),
 41→	}
 42→	// Apply options before reading headers so delimiter etc. take effect.
 43→	for _, o := range opts {
 44→		o(cr)
 45→	}
 46→
 47→	headers, err := cr.csv.Read()
 48→	if err != nil {
 49→		return nil, fmt.Errorf("csvutil: read headers: %w", err)
 50→	}
 51→
 52→	cr.headers = make(map[string]int, len(headers))
 53→	for i, h := range headers {
 54→		cr.headers[h] = i
 55→	}
 56→
 57→	return cr, nil
 58→}
 59→
 60→// Next advances to the next record and returns a Row for it.
 61→// Returns (Row{}, false, nil) at EOF.
 62→func (r *Reader) Next() (Row, bool, error) {
 63→	record, err := r.csv.Read()
 64→	if err == io.EOF {
 65→		return Row{}, false, nil
 66→	}
 67→	if err != nil {
 68→		return Row{}, false, fmt.Errorf("csvutil: read row: %w", err)
 69→	}
 70→	return Row{values: record, headers: r.headers}, true, nil
 71→}
 72→
 73→// Row holds one parsed record with header-mapped field accessors.
 74→// All accessors are silent on missing columns: they return the zero value or nil.
 75→type Row struct {
 76→	values  []string
 77→	headers map[string]int
 78→}
 79→
 80→// raw returns the raw string value for col, and whether the column exists.
 81→func (r Row) raw(col string) (string, bool) {
 82→	idx, ok := r.headers[col]
 83→	if !ok || idx >= len(r.values) {
 84→		return "", false
 85→	}
 86→	return r.values[idx], true
 87→}
 88→
 89→// String returns the string value of col, or "" if the column is absent.
 90→func (r Row) String(col string) string {
 91→	v, _ := r.raw(col)
 92→	return v
 93→}
 94→
 95→// Int parses col as an integer, returning 0 on missing column or parse error.
 96→func (r Row) Int(col string) int {
 97→	v, ok := r.raw(col)
 98→	if !ok || v == "" {
 99→		return 0
100→	}
101→	n, err := strconv.Atoi(v)
102→	if err != nil {
103→		return 0
104→	}
105→	return n
106→}
107→
108→// Float parses col as a float64, returning 0 on missing column or parse error.
109→func (r Row) Float(col string) float64 {
110→	v, ok := r.raw(col)
111→	if !ok || v == "" {
112→		return 0
113→	}
114→	f, err := strconv.ParseFloat(v, 64)
115→	if err != nil {
116→		return 0
117→	}
118→	return f
119→}
120→
121→// OptionalString returns a pointer to the string value of col, or nil if the
122→// column is absent or the value is empty.
123→func (r Row) OptionalString(col string) *string {
124→	v, ok := r.raw(col)
125→	if !ok || v == "" {
126→		return nil
127→	}
128→	return &v
129→}
130→
131→// OptionalInt parses col as an integer and returns a pointer to the result, or
132→// nil if the column is absent, empty, or not parseable as an integer.
133→func (r Row) OptionalInt(col string) *int {
134→	v, ok := r.raw(col)
135→	if !ok || v == "" {
136→		return nil
137→	}
138→	n, err := strconv.Atoi(v)
139→	if err != nil {
140→		return nil
141→	}
142→	return &n
143→}
144→
145→// OptionalFloat parses col as a float64 and returns a pointer to the result,
146→// or nil if the column is absent, empty, or not parseable as a float.
147→func (r Row) OptionalFloat(col string) *float64 {
148→	v, ok := r.raw(col)
149→	if !ok || v == "" {
150→		return nil
151→	}
152→	f, err := strconv.ParseFloat(v, 64)
153→	if err != nil {
